import { gs } from '@servicenow/glide'

var GitHubValidationAjax = Class.create();
GitHubValidationAjax.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {

    /**
     * Validate GitHub repository access from client-side
     */
    validateRepository: function() {
        try {
            var repoUrl = this.getParameter('sysparm_repo_url');
            var branch = this.getParameter('sysparm_branch') || 'main';
            var token = this.getParameter('sysparm_token');

            if (!repoUrl) {
                return JSON.stringify({
                    success: false,
                    error: 'Repository URL is required'
                });
            }

            // Import GitHubAPI for validation
            var GitHubAPI = require('../github/github-api.js').GitHubAPI;
            var githubAPI = new GitHubAPI(token);

            // Validate repository
            var validation = githubAPI.validateRepository(repoUrl, branch);

            if (!validation.success) {
                return JSON.stringify({
                    success: false,
                    error: validation.error
                });
            }

            // Extract repository information
            var suggestedScope = null;
            var message = 'Repository is accessible';

            if (validation.repository) {
                var repo = validation.repository;
                message = 'Repository: ' + repo.full_name + ', Branch: ' + branch + ', Last updated: ' + repo.updated_at;

                // Suggest a scope name based on repository name
                suggestedScope = 'x_custom_' + repo.name.toLowerCase().replace(/[^a-z0-9]/g, '_');
            }

            return JSON.stringify({
                success: true,
                message: message,
                suggested_scope: suggestedScope,
                repository_info: validation.repository
            });

        } catch (error) {
            gs.error('GitHubValidationAjax.validateRepository error: ' + error.message);
            return JSON.stringify({
                success: false,
                error: 'Validation failed: ' + error.message
            });
        }
    },

    /**
     * Get available branches for a repository
     */
    getBranches: function() {
        try {
            var repoUrl = this.getParameter('sysparm_repo_url');
            var token = this.getParameter('sysparm_token');

            if (!repoUrl) {
                return JSON.stringify({
                    success: false,
                    error: 'Repository URL is required'
                });
            }

            var GitHubAPI = require('../github/github-api.js').GitHubAPI;
            var githubAPI = new GitHubAPI(token);

            // Parse repository URL
            var parsed = GitHubAPI.parseRepoUrl(repoUrl);
            if (!parsed.success) {
                return JSON.stringify(parsed);
            }

            // Get branches
            var branchResponse = githubAPI.getBranches(parsed.owner, parsed.repo);
            if (!branchResponse.success) {
                return JSON.stringify({
                    success: false,
                    error: 'Failed to fetch branches'
                });
            }

            var branches = JSON.parse(branchResponse.body);
            var branchList = [];
            for (var i = 0; i < branches.length; i++) {
                branchList.push({
                    name: branches[i].name,
                    commit_sha: branches[i].commit.sha
                });
            }

            return JSON.stringify({
                success: true,
                branches: branchList
            });

        } catch (error) {
            gs.error('GitHubValidationAjax.getBranches error: ' + error.message);
            return JSON.stringify({
                success: false,
                error: 'Failed to get branches: ' + error.message
            });
        }
    },

    type: 'GitHubValidationAjax'
});
